    protected_threads = {}

    @staticmethod
    def start_protection():
        current_thread = threading.current_thread()
        AntiSSRF.protected_threads[current_thread] = True
        socket.socket.connect = new_socket_connect

    @staticmethod
    def stop_protection():
        current_thread = threading.current_thread()
        AntiSSRF.protected_threads.pop(current_thread, None)
        socket.socket.connect = origin_socket_connect

def get_weather_from_provider(api_url: str) -> dict:
    """
    Fetches weather data from a specified API provider with SSRF protection.

    Args:
        api_url: The URL of the weather data provider's API endpoint

    Returns:
        A dictionary containing the weather data from the API response

